#include<bits/stdc++.h>
using namespace std;
bool vis[510][510];
char a[510][510];
int dx[4]={1,0,-1,0};
int dy[4]={0,1,0,-1};
int ax,ay,bx,by;
struct node
{
    int x,y,step;
};
int main()
{
    int n,m;
    while(scanf("%d%d",&n,&m)==2&&n)
    {
        memset(vis,0,sizeof(vis));
        for(int i=1;i<=n;i++)
        {
            scanf("%s",a[i]+1);
        }
        scanf("%d%d%d%d",&ax,&ay,&bx,&by);
        ax++;
        ay++;
        bx++;
        by++;
        deque<node> q;
        q.push_back((node){ax,ay});
        while(!q.empty())
        {
            node t=q.front();
            q.pop_front();
            if(t.x==bx&&t.y==by)
            {
                printf("%d\n",t.step);
                break;
            }
            for(int i=0;i<4;i++)
            {
                node t1=(node){t.x+dx[i],t.y+dy[i],t.step};
                if(t1.x<1||t1.x>n||t1.y<1||t1.y>m||vis[t1.x][t1.y])
                {
                    continue;
                }
                vis[t1.x][t1.y]=1;
                if(a[t.x][t.y]!=a[t1.x][t1.y])
                {
                    t1.step++;
                    q.push_back(t1);
                }
                else
                {
                    q.push_front(t1);
                }
            }
        }
    }
    return 0;
}
